import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import useScanners from '../hooks/useScanners';
import useSignalTier from '../hooks/useSignalTier';
import LoadingState from '../components/LoadingState';
import ExportBar from '../components/ExportBar';
import SymbolSearch from '../components/SymbolSearch';
import usePageTitle from '../hooks/usePageTitle';
import SignalTierBadge from '../components/SignalTierBadge';
import SignalDelayBanner from '../components/SignalDelayBanner';
import SignalLimitOverlay from '../components/SignalLimitOverlay';
import SignalAnalysisLock from '../components/SignalAnalysisLock';
import RegulatoryDisclaimer from '../components/RegulatoryDisclaimer';
import DataFreshness from '../components/DataFreshness';
import { SkeletonTable } from '../components/Skeleton';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';

const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, mono: tokens.font.mono, sans: tokens.font.sans,
};

const POLL_INTERVAL = 30_000;

function fmt(val, d = 2) { return val == null || isNaN(val) ? '--' : Number(val).toFixed(d); }
function fmtPct(val) { return val == null || isNaN(val) ? '--' : (Number(val) * 100).toFixed(1) + '%'; }
function fmtVol(val) {
  if (val == null || isNaN(val)) return '--';
  const n = Number(val);
  if (n >= 1e6) return (n / 1e6).toFixed(1) + 'M';
  if (n >= 1e3) return (n / 1e3).toFixed(0) + 'K';
  return n.toLocaleString();
}

function ratioColor(val) {
  if (val >= 3) return T.green;
  if (val >= 1.5) return T.amber;
  return T.text;
}

function getTierBadge(confidence) {
  if (confidence == null) return null;
  const pct = confidence > 1 ? confidence : confidence * 100;
  if (pct >= 97) return { label: 'ULTRA', bg: 'rgba(167,139,250,0.15)', color: '#A78BFA', border: 'rgba(167,139,250,0.3)' };
  if (pct >= 90) return { label: 'HIGH CONVICTION', bg: 'rgba(34,197,94,0.12)', color: '#22C55E', border: 'rgba(34,197,94,0.25)' };
  return { label: 'STANDARD', bg: 'rgba(96,165,250,0.10)', color: '#60A5FA', border: 'rgba(96,165,250,0.2)' };
}

function TierBadge({ confidence }) {
  const tier = getTierBadge(confidence);
  if (!tier) return <span style={{ color: T.textSec, fontSize: 11 }}>--</span>;
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 4,
      background: tier.bg, color: tier.color, border: `1px solid ${tier.border}`,
      borderRadius: 4, padding: '2px 7px', fontSize: 10, fontWeight: 700,
      whiteSpace: 'nowrap', fontFamily: T.mono, letterSpacing: '0.04em',
    }}>
      {tier.label}
    </span>
  );
}

function EnsembleBadge({ data, loading }) {
  if (loading) {
    return (
      <span style={{
        display: 'inline-block', width: 72, height: 20, borderRadius: 4,
        background: T.surface2, verticalAlign: 'middle',
      }} />
    );
  }
  if (!data) return <span style={{ color: T.textSec, fontSize: 11 }}>--</span>;
  const { score, direction } = data;
  const isLong = direction === 'LONG';
  const isShort = direction === 'SHORT';
  const color = isLong ? T.green : isShort ? T.red : T.textSec;
  const bg = isLong ? 'rgba(34,197,94,0.12)' : isShort ? 'rgba(239,68,68,0.12)' : 'rgba(144,163,175,0.10)';
  const arrow = isLong ? '\u2191' : isShort ? '\u2193' : '\u2014';
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 4,
      background: bg, color, border: `1px solid ${color}44`,
      borderRadius: 4, padding: '2px 7px', fontSize: 11, fontWeight: 700,
      whiteSpace: 'nowrap', fontFamily: T.mono,
    }}>
      {arrow} {score.toFixed(2)} {direction}
    </span>
  );
}

const S = {
  page: { padding: '24px 32px', fontFamily: T.sans, minHeight: '100vh' },
  title: { margin: 0, fontSize: 28, fontWeight: 700, color: T.text },
  subtitle: { margin: '6px 0 0', fontSize: 13, color: T.textSec },
  filterBar: {
    display: 'flex', alignItems: 'flex-end', gap: 16, flexWrap: 'wrap',
    padding: '14px 0', marginBottom: 8,
  },
  filterLabel: { display: 'flex', flexDirection: 'column', gap: 4, fontSize: 11, fontWeight: 600, color: T.textSec, textTransform: 'uppercase', letterSpacing: '0.04em' },
  filterInput: {
    background: T.surface, border: `1px solid ${T.border}`, borderRadius: 6,
    color: T.text, padding: '6px 10px', fontSize: 13, fontFamily: T.mono, width: 100,
    outline: 'none',
  },
  filterSelect: {
    background: T.surface, border: `1px solid ${T.border}`, borderRadius: 6,
    color: T.text, padding: '6px 10px', fontSize: 13, fontFamily: T.mono,
    outline: 'none', cursor: 'pointer',
  },
  refreshBtn: {
    background: T.green, color: T.bg, border: 'none', borderRadius: 6,
    padding: '7px 18px', fontSize: 12, fontWeight: 700, fontFamily: T.mono,
    cursor: 'pointer', letterSpacing: '0.03em',
  },
  refreshBtnDisabled: { opacity: 0.5, cursor: 'not-allowed' },
  tableWrap: { overflowX: 'auto', borderRadius: 12, border: `1px solid ${T.border}` },
  table: { width: '100%', borderCollapse: 'collapse', fontSize: 13, fontFamily: T.mono },
  th: {
    padding: '12px 14px', textAlign: 'left', color: T.textSec, fontWeight: 600,
    fontSize: 11, textTransform: 'uppercase', letterSpacing: '0.05em',
    borderBottom: `1px solid ${T.border}`, background: T.surface,
  },
  td: { padding: '10px 14px', borderBottom: `1px solid ${T.border}22` },
  symbolCell: { padding: '10px 14px', fontWeight: 700, color: T.blue, borderBottom: `1px solid ${T.border}22` },
  strategyCell: { padding: '10px 14px', color: T.text, fontFamily: T.sans, fontSize: 12, borderBottom: `1px solid ${T.border}22` },
  barTrack: { width: 60, height: 6, borderRadius: 6, background: T.surface2, overflow: 'hidden' },
  emptyState: {
    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
    padding: 60, gap: 16, color: T.textSec,
  },
  signalCount: {
    display: 'inline-flex', alignItems: 'center', gap: 6,
    padding: '4px 12px', borderRadius: 20, fontSize: 11, fontWeight: 600,
    fontFamily: T.mono, background: 'rgba(34,197,94,0.08)', color: T.green,
    border: '1px solid rgba(34,197,94,0.15)',
  },
};

export default function ScannerVolumePage() {
  usePageTitle('Scanner: Volume');
  const navigate = useNavigate();
  const { results, loading: scannerLoading, runScanner } = useScanners();
  const signalTier = useSignalTier();

  const [minRatio, setMinRatio] = useState('');
  const [sortBy, setSortBy] = useState('volume_ratio');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [ensembleScores, setEnsembleScores] = useState({});
  const [ensembleLoading, setEnsembleLoading] = useState(false);
  const [lastScanTime, setLastScanTime] = useState(null);
  const [signalCount, setSignalCount] = useState(0);
  const pollRef = useRef(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      await runScanner('unusual_volume');
    } catch (err) {
      setError(err.message || 'Error fetching scanner data');
    }
  }, [runScanner]);

  // Initial fetch
  useEffect(() => { fetchData(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Auto-refresh polling (30s)
  useEffect(() => {
    pollRef.current = setInterval(() => {
      runScanner('unusual_volume').catch(() => {});
    }, POLL_INTERVAL);
    return () => clearInterval(pollRef.current);
  }, [runScanner]);

  // Sync loading state
  useEffect(() => {
    setLoading(scannerLoading);
    if (!scannerLoading && results) {
      setLastScanTime(Date.now());
      setSignalCount(Array.isArray(results) ? results.length : 0);
    }
  }, [scannerLoading, results]);

  // Fetch ensemble scores
  const fetchEnsembleScores = useCallback(async (rows) => {
    if (!rows || rows.length === 0) return;
    const symbols = [...new Set(rows.map((r) => r.symbol).filter(Boolean))];
    if (symbols.length === 0) return;
    setEnsembleLoading(true);
    try {
      const batchData = await api('/ensemble/current', { silent: true });
      if (batchData && typeof batchData === 'object') {
        const map = {};
        const scores = batchData.scores || batchData;
        symbols.forEach((sym) => {
          const entry = scores[sym] || scores[sym.toUpperCase()];
          if (entry) {
            const raw = entry.ensemble_score ?? entry.score ?? entry;
            const score = typeof raw === 'number' ? raw : parseFloat(raw);
            if (!isNaN(score)) {
              map[sym] = { score, direction: entry.direction || (score > 0.1 ? 'LONG' : score < -0.1 ? 'SHORT' : 'NEUTRAL') };
            }
          }
        });
        setEnsembleScores(map);
        setEnsembleLoading(false);
        return;
      }
      const fetched = await Promise.all(
        symbols.map((sym) =>
          api(`/ensemble/score/${encodeURIComponent(sym)}`, { silent: true }).then((data) => ({ sym, data })).catch(() => ({ sym, data: null }))
        )
      );
      const map = {};
      fetched.forEach(({ sym, data }) => {
        const raw = data?.ensemble_score ?? data?.score;
        if (data && raw != null) {
          map[sym] = { score: raw, direction: data.direction || (raw > 0.1 ? 'LONG' : raw < -0.1 ? 'SHORT' : 'NEUTRAL') };
        }
      });
      setEnsembleScores(map);
    } catch {
      // silent
    }
    setEnsembleLoading(false);
  }, []);

  useEffect(() => {
    if (!scannerLoading && results && results.length > 0) {
      fetchEnsembleScores(results);
    }
  }, [scannerLoading, results, fetchEnsembleScores]);

  const filtered = useMemo(() => {
    if (!results || !Array.isArray(results)) return [];
    let out = results.filter(r => {
      if (minRatio && (r.volume_ratio ?? r.signal_strength ?? 0) < Number(minRatio)) return false;
      return true;
    });
    if (sortBy === 'ensemble_score') {
      out.sort((a, b) => {
        const sa = Math.abs(ensembleScores[a.symbol]?.score ?? 0);
        const sb = Math.abs(ensembleScores[b.symbol]?.score ?? 0);
        return sb - sa;
      });
    } else {
      out.sort((a, b) => (b[sortBy] ?? 0) - (a[sortBy] ?? 0));
    }
    return out;
  }, [results, minRatio, sortBy, ensembleScores]);

  const { visible: visibleSignals, hidden: hiddenCount, total: totalCount } = signalTier.applyLimit(filtered);

  const handleRowClick = (row) => navigate(`/charts?symbol=${encodeURIComponent(row.symbol)}`);
  const handleSymbolSelect = (symbol) => navigate(`/charts?symbol=${encodeURIComponent(symbol)}`);

  return (
    <LoadingState loading={loading} error={error}
      empty={!results || (results && results.length === 0)} type="table" onRetry={fetchData}>
      <div style={S.page}>
        <SignalDelayBanner />

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 12, marginBottom: 8 }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap' }}>
              <h1 style={S.title}>Unusual Volume Scanner</h1>
              <SignalTierBadge />
              {lastScanTime && <DataFreshness lastUpdated={lastScanTime} label="Scanner" />}
              {signalCount > 0 && (
                <span style={S.signalCount}>{signalCount} signal{signalCount !== 1 ? 's' : ''}</span>
              )}
            </div>
            <p style={S.subtitle}>
              Stocks trading at abnormally high volume relative to their average
            </p>
          </div>
          <div style={{ maxWidth: 260 }}>
            <SymbolSearch compact onSelect={handleSymbolSelect} placeholder="Jump to chart..." />
          </div>
        </div>

        {/* Filter bar */}
        <div style={S.filterBar}>
          <label style={S.filterLabel}>
            Min Volume Ratio
            <input type="number" step="0.5" value={minRatio} onChange={e => setMinRatio(e.target.value)}
              placeholder="e.g. 2.0" style={S.filterInput} />
          </label>
          <label style={S.filterLabel}>
            Sort By
            <select value={sortBy} onChange={e => setSortBy(e.target.value)} style={S.filterSelect}>
              <option value="volume_ratio">Volume Ratio</option>
              <option value="signal_strength">Signal Strength</option>
              <option value="total_return">Price Change</option>
              <option value="trades">Volume</option>
              <option value="ensemble_score">Ensemble Score</option>
            </select>
          </label>

          {!loading && filtered.length > 0 && (
            <span style={{ fontSize: 12, color: T.textSec }}>
              Showing {visibleSignals.length} of {totalCount} signal{totalCount !== 1 ? 's' : ''}
            </span>
          )}

          <button onClick={fetchData} disabled={loading}
            style={{ ...S.refreshBtn, ...(loading ? S.refreshBtnDisabled : {}) }}>
            {loading ? 'Scanning...' : 'Refresh'}
          </button>
        </div>

        {/* Loading skeleton */}
        {loading && <SkeletonTable rows={8} columns={9} />}

        {/* Results table */}
        {!loading && visibleSignals.length > 0 && (
          <>
            <ExportBar data={visibleSignals} filename="unusual-volume-export"
              columns={['Symbol', 'Strategy', 'Volume Ratio', 'Tier', 'Avg Volume', 'Current Volume', 'Price Change', 'Signal Strength', 'Ensemble']} />
            <div style={S.tableWrap}>
              <table style={S.table}>
                <thead>
                  <tr>
                    {['Symbol', 'Strategy', 'Volume Ratio', 'Tier', 'Avg Volume', 'Current Volume', 'Price Change', 'Signal Strength', 'Ensemble'].map(h => (
                      <th key={h} style={S.th}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {visibleSignals.map((row, idx) => {
                    const isDelayed = signalTier.isDelayed;
                    const confidence = row.win_rate != null ? row.win_rate : (row.signal_strength ? row.signal_strength / 100 : null);
                    return (
                      <React.Fragment key={idx}>
                        <tr onClick={() => handleRowClick(row)} style={{
                          cursor: 'pointer', opacity: isDelayed ? 0.65 : 1,
                          background: idx % 2 === 0 ? 'transparent' : 'rgba(34,197,94,0.02)',
                          transition: 'background 150ms ease',
                        }}
                        onMouseEnter={(e) => { e.currentTarget.style.background = T.surface2; }}
                        onMouseLeave={(e) => { e.currentTarget.style.background = idx % 2 === 0 ? 'transparent' : 'rgba(34,197,94,0.02)'; }}>
                          <td style={S.symbolCell}>{row.symbol}</td>
                          <td style={S.strategyCell}>{(row.strategy || '--').replace(/_/g, ' ')}</td>
                          <td style={{ ...S.td, fontWeight: 700, color: ratioColor(row.volume_ratio ?? row.signal_strength ?? 0) }}>
                            {fmt(row.volume_ratio ?? row.signal_strength, 1)}x
                          </td>
                          <td style={S.td}><TierBadge confidence={confidence} /></td>
                          <td style={{ ...S.td, color: T.text }}>{fmtVol(row.avg_volume)}</td>
                          <td style={{ ...S.td, color: T.text, fontWeight: 600 }}>{fmtVol(row.current_volume ?? row.trades)}</td>
                          <td style={{ ...S.td, color: (row.total_return ?? 0) > 0 ? T.green : T.red, fontWeight: 600 }}>
                            {fmtPct(row.total_return)}
                          </td>
                          <td style={S.td}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                              <div style={S.barTrack}>
                                <div style={{
                                  width: `${Math.min(100, Math.max(0, (row.signal_strength ?? 0)))}%`,
                                  height: '100%', borderRadius: 6,
                                  background: ratioColor(row.signal_strength ?? 0),
                                }} />
                              </div>
                              <span style={{ fontSize: 12, fontWeight: 600 }}>
                                {fmt(row.signal_strength, 0)}
                              </span>
                            </div>
                          </td>
                          <td style={S.td}>
                            <EnsembleBadge data={ensembleScores[row.symbol]} loading={ensembleLoading && !ensembleScores[row.symbol]} />
                          </td>
                        </tr>
                        <tr>
                          <td colSpan={9} style={{ padding: 0, border: 'none' }}>
                            <SignalAnalysisLock row={row} />
                          </td>
                        </tr>
                      </React.Fragment>
                    );
                  })}
                </tbody>
              </table>
            </div>

            <SignalLimitOverlay hiddenCount={hiddenCount} totalCount={totalCount} visibleCount={visibleSignals.length} />
          </>
        )}

        {/* Empty state */}
        {!loading && filtered.length === 0 && (
          <div style={S.emptyState}>
            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M3 3v18h18" /><path d="M7 16l4-8 4 4 4-6" />
            </svg>
            <p style={{ fontSize: 16, fontWeight: 600, color: T.text }}>No unusual volume signals found</p>
            <p style={{ fontSize: 13 }}>Try adjusting filters or refresh the scanner</p>
          </div>
        )}

        <RegulatoryDisclaimer compact />
      </div>
    </LoadingState>
  );
}
